#include "vimax/modules/cheese_module.hpp"
namespace vimax {std::string CheeseModule::id() const{return "vimax.cheese";}std::string CheeseModule::name() const{return "Vimax Cheese";}std::vector<std::string> CheeseModule::supported_intents() const{return {"cheese.start_batch"};}WorkflowPlan CheeseModule::build_plan(const Intent&i) const{WorkflowPlan p;p.id="cheese.start_batch.v1";p.title="Начать новую варку сыра";if(!i.slots.contains("recipe"))p.missing_fields.push_back("recipe");if(!i.slots.contains("milk_liters"))p.missing_fields.push_back("milk_liters");p.actions.push_back({id(),"create_batch",i.slots,RiskLevel::low,ConfirmationMode::none});p.executable=p.missing_fields.empty();return p;}ActionResult CheeseModule::execute(const Action&a){if(a.operation!="create_batch")return {false,"Неизвестная операция сыроварения",{}};return {true,"Черновик варки создан. Следующий этап — загрузка рецепта и расчёт ингредиентов.",{{"batch_status","draft"}}};}}
